import{_ as e,o as i,c as t,S as s}from"./chunks/framework.C6RQlTYc.js";const g=JSON.parse('{"title":"RAG（检索增强生成）","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_23-rag.md","filePath":"直击概念/17ai/s_ai_23-rag.md","lastUpdated":1778207238000}'),n={name:"直击概念/17ai/s_ai_23-rag.md"};function r(l,a,d,o,h,p){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="rag-检索增强生成" tabindex="-1">RAG（检索增强生成） <a class="header-anchor" href="#rag-检索增强生成" aria-label="Permalink to &quot;RAG（检索增强生成）&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>RAG（Retrieval-Augmented Generation，检索增强生成）是一种让 LLM <strong>基于外部知识库回答问题</strong>的技术，工作流程是：<strong>先检索相关文档，再将文档内容注入 prompt 让 LLM 基于此生成答案</strong>。</p><p>RAG 解决了 LLM 的两大核心问题：</p><ol><li><strong>知识时效性</strong>：LLM 训练数据有截止日期，无法回答新知识</li><li><strong>幻觉问题</strong>：让 LLM 基于真实文档回答，大幅降低编造</li></ol><h2 id="工作流程" tabindex="-1">工作流程 <a class="header-anchor" href="#工作流程" aria-label="Permalink to &quot;工作流程&quot;">​</a></h2><h3 id="naive-rag-三步走" tabindex="-1">Naive RAG 三步走 <a class="header-anchor" href="#naive-rag-三步走" aria-label="Permalink to &quot;Naive RAG 三步走&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>用户提问 → 向量检索 → 获取相关文档 → 构造增强 prompt → LLM 生成 → 答案</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="详细流程" tabindex="-1">详细流程 <a class="header-anchor" href="#详细流程" aria-label="Permalink to &quot;详细流程&quot;">​</a></h3><p><strong>1. 文档预处理（离线/Indexing）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>原始文档 → 分块(Chunking) → Embedding向量化 → 存入向量数据库</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>文档按语义边界拆分为合适的 chunks（通常 256~1024 tokens）</li><li>每个 chunk 通过 Embedding 模型转为向量</li><li>向量和原始文本一起存入向量数据库</li></ul><p><strong>2. 检索（Retrieval，在线）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>用户问题 → Embedding向量化 → 向量数据库相似度搜索 → Top-K 相关文档</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>将用户问题也转为 Embedding 向量</li><li>用余弦相似度在向量库中找到最相关的 K 个文档片段</li></ul><p><strong>3. 增强生成（Augmented Generation，在线）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>系统指令 + 检索到的文档上下文 + 用户问题 → LLM → 基于上下文的答案</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>构造 prompt：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>基于以下参考资料回答问题。如果资料中找不到答案，请说&quot;资料中未提供相关信息&quot;。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>参考资料：</span></span>
<span class="line"><span>[检索到的文档内容]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>问题：[用户问题]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="核心组件" tabindex="-1">核心组件 <a class="header-anchor" href="#核心组件" aria-label="Permalink to &quot;核心组件&quot;">​</a></h2><h3 id="文档分块-chunking" tabindex="-1">文档分块（Chunking） <a class="header-anchor" href="#文档分块-chunking" aria-label="Permalink to &quot;文档分块（Chunking）&quot;">​</a></h3><p>分块策略直接影响检索质量：</p><table><thead><tr><th>策略</th><th>描述</th><th>适用场景</th></tr></thead><tbody><tr><td>固定大小</td><td>每 N 个 token 一刀</td><td>通用</td></tr><tr><td>语义分块</td><td>按段落/句子边界</td><td>长文档</td></tr><tr><td>滑动窗口</td><td>相邻块有一定重叠</td><td>避免截断关键信息</td></tr><tr><td>层级分块</td><td>父子块结构</td><td>大文档精确检索</td></tr></tbody></table><h3 id="检索方式" tabindex="-1">检索方式 <a class="header-anchor" href="#检索方式" aria-label="Permalink to &quot;检索方式&quot;">​</a></h3><ul><li><strong>向量检索（稠密检索）</strong>：语义相似度，召回率高</li><li><strong>关键词检索（稀疏检索/BM25）</strong>：精确匹配，互补</li><li><strong>混合检索</strong>：向量 + 关键词，取交集或加权合并</li></ul><h3 id="重排序-re-ranking" tabindex="-1">重排序（Re-ranking） <a class="header-anchor" href="#重排序-re-ranking" aria-label="Permalink to &quot;重排序（Re-ranking）&quot;">​</a></h3><p>对检索结果进行二次精排，用更强的模型重新打分：</p><ul><li>Cross-Encoder 模型（如 Cohere Rerank、bge-reranker）</li><li>有效提升 Top-K 结果的相关性</li></ul><h2 id="前端实践" tabindex="-1">前端实践 <a class="header-anchor" href="#前端实践" aria-label="Permalink to &quot;前端实践&quot;">​</a></h2><h3 id="适合前端实现的-rag" tabindex="-1">适合前端实现的 RAG <a class="header-anchor" href="#适合前端实现的-rag" aria-label="Permalink to &quot;适合前端实现的 RAG&quot;">​</a></h3><ul><li><strong>客户端向量检索</strong>：小规模知识库可用 Transformers.js 在浏览器中做 Embedding + 检索</li><li><strong>服务端 RAG + 前端流式展示</strong>：后端处理检索和 LLM 调用，前端展示带引用标注的流式回答</li><li><strong>Edge RAG</strong>：在 Cloudflare Workers 等边缘节点实现轻量 RAG</li></ul><h3 id="ui-设计要点" tabindex="-1">UI 设计要点 <a class="header-anchor" href="#ui-设计要点" aria-label="Permalink to &quot;UI 设计要点&quot;">​</a></h3><ul><li>展示检索到的<strong>引用来源</strong>（链接、高亮原文）</li><li>区分&quot;基于资料的回答&quot;和&quot;模型推断&quot;</li><li>对没有找到相关信息的情况给出清晰提示</li></ul><h2 id="高级-rag-模式" tabindex="-1">高级 RAG 模式 <a class="header-anchor" href="#高级-rag-模式" aria-label="Permalink to &quot;高级 RAG 模式&quot;">​</a></h2><table><thead><tr><th>模式</th><th>描述</th></tr></thead><tbody><tr><td>Self-RAG</td><td>模型自行判断是否需要检索</td></tr><tr><td>Corrective RAG</td><td>评估检索质量，质量不够时回退到搜索</td></tr><tr><td>Graph RAG</td><td>结合知识图谱增强检索</td></tr><tr><td>Agentic RAG</td><td>多步检索、跨文档推理</td></tr></tbody></table><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>RAG 解决的核心问题是什么？</li><li>Naive RAG 的三个阶段各做了什么？</li><li>前端如何实现一个简单的 RAG 系统？有哪些限制？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2005.11401" target="_blank" rel="noreferrer">Retrieval-Augmented Generation for Knowledge-Intensive NLP Tasks</a></li><li><a href="https://python.langchain.com/docs/tutorials/rag/" target="_blank" rel="noreferrer">LangChain RAG Tutorial</a></li><li><a href="https://docs.llamaindex.ai/" target="_blank" rel="noreferrer">LlamaIndex</a></li></ul>`,39)])])}const c=e(n,[["render",r]]);export{g as __pageData,c as default};
